package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.assertEquals;

import java.lang.reflect.Constructor;
import org.junit.jupiter.api.Test;

class LineItemTest {

  @Test
  void testToString() throws Exception {
    String name = "Apple";
    int quantity = 3;
    long priceInMicros = 2500000L; // 2.5 in normal units
    String currencyCode = "USD";

    // Directly use the LineItem class instead of Class.forName
    Constructor<LineItem> ctor = LineItem.class.getDeclaredConstructor(String.class, int.class, long.class, String.class);
    LineItem lineItem = ctor.newInstance(name, quantity, priceInMicros, currencyCode);

    String expected = String.format("(item: %s, qty: %s, price: %.2f %s)",
        name, quantity, priceInMicros / 1000000d, currencyCode);

    String actual = lineItem.toString();
    assertEquals(expected, actual);
  }
}
